#ifndef DEFAULT_ORDER
#define DEFAULT_ORDER 256
#endif

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    char is_leaf;
    int num_keys;
} knode;

__kernel void findK(const long maxheight,
                    __global knode *knodes,
                    const long knodes_elem,
                    __global record *records,
                    __global long *currKnode,
                    __global long *offset,
                    __global int *keys,
                    __global record *ans) {
    const int bid = (int)get_group_id(0);
    const int thid = (int)get_local_id(0);

    for (long i = 0; i < maxheight; i++) {
        if ((knodes[currKnode[bid]].keys[thid] <= keys[bid]) &&
            (knodes[currKnode[bid]].keys[thid + 1] > keys[bid])) {
            int idx = knodes[offset[bid]].indices[thid];
            if ((long)idx < knodes_elem) {
                offset[bid] = (long)idx;
            }
        }

        barrier(CLK_GLOBAL_MEM_FENCE);
        if (thid == 0) {
            currKnode[bid] = offset[bid];
        }
        barrier(CLK_GLOBAL_MEM_FENCE);
    }

    if (knodes[currKnode[bid]].keys[thid] == keys[bid]) {
        ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
    }
}

