                                 __global long *offset_2,
                                 __global int *start,
                                 __global int *end,
                                 __global int *recstart,
                                 __global int *reclength) {
    const int bid = (int)get_group_id(0);
    const int thid = (int)get_local_id(0);

    for (long i = 0; i < maxheight; i++) {
        if ((knodes[currKnode[bid]].keys[thid] <= start[bid]) &&
            (knodes[currKnode[bid]].keys[thid + 1] > start[bid])) {
            int idx = knodes[currKnode[bid]].indices[thid];
            if ((long)idx < knodes_elem) {
                offset[bid] = (long)idx;
            }
        }

        if ((knodes[lastKnode[bid]].keys[thid] <= end[bid]) &&
            (knodes[lastKnode[bid]].keys[thid + 1] > end[bid])) {
            int idx2 = knodes[lastKnode[bid]].indices[thid];
            if ((long)idx2 < knodes_elem) {
                offset_2[bid] = (long)idx2;
            }
        }

        barrier(CLK_GLOBAL_MEM_FENCE);
